import{_ as a,o as i,c as s,ag as n}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Media tensión","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/distribution/medium-voltage.md","filePath":"es/power-systems/distribution/medium-voltage.md"}'),o={name:"es/power-systems/distribution/medium-voltage.md"};function r(t,e,l,c,d,p){return i(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="media-tension" tabindex="-1">Media tensión <a class="header-anchor" href="#media-tension" aria-label="Permalink to &quot;Media tensión&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los sistemas de media tensión (MV) se utilizan para distribuir energía eléctrica a niveles de voltaje más altos dentro de instalaciones industriales.</p><p>Típicamente operan en el rango de 1 kV a 36 kV, dependiendo de las normas regionales y los requisitos de la aplicación.</p><p>La media tensión se utiliza para transportar energía de manera eficiente a largas distancias y para alimentar cargas grandes antes de reducir a baja tensión.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de los sistemas de media tensión es:</p><ul><li>Reducir la corriente para un nivel de potencia dado, minimizando las pérdidas</li><li>Permitir distribución eficiente en instalaciones grandes</li><li>Alimentar equipo de alta potencia directamente cuando se requiere</li><li>Proporcionar una interfaz estructurada entre el suministro del servicio público y la distribución interna</li></ul><p>El uso de niveles de voltaje más altos permite conductores más compactos y mayor eficiencia del sistema.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La energía eléctrica ingresa a la instalación desde el servicio público, generalmente a media tensión.</p><p>A partir de ahí, el sistema distribuye energía a través de:</p><ul><li>Switchgear (celdas de media tensión) para control y protección</li><li>Alimentadores que suministran diferentes áreas o procesos</li><li>Transformadores que reducen el voltaje a niveles de baja tensión</li><li>Conexiones directas a equipo grande como motores o subestaciones</li></ul><p>Los sistemas de protección monitorean corriente y voltaje para detectar fallas y aislar las secciones afectadas.</p><p>Los dispositivos de conmutación permiten energizar o desenergizar secciones del sistema de manera segura.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los sistemas de media tensión se utilizan en:</p><ul><li>Plantas industriales grandes con demanda de potencia significativa</li><li>Instalaciones de minería, petróleo y gas, y manufactura pesada</li><li>Instalaciones con largas distancias entre cargas</li><li>Aplicaciones de motores de alta potencia como compresores y molinos</li><li>Redes de distribución interna en campus o complejos grandes</li></ul><p>Son esenciales donde la distribución en baja tensión resultaría en corrientes excesivas y pérdidas.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Selección del nivel de voltaje</strong><br> Debe equilibrar eficiencia, costo del equipo y compatibilidad con el suministro del servicio público</p></li><li><p><strong>Aislamiento y distancias de seguridad</strong><br> Un voltaje más alto requiere un diseño de aislamiento más estricto y mayor separación física</p></li><li><p><strong>Sistemas de protección</strong><br> Más complejos que en baja tensión, a menudo involucran relevadores y esquemas coordinados</p></li><li><p><strong>Niveles de cortocircuito</strong><br> Las corrientes de falla pueden ser muy altas y deben considerarse en las capacidades del equipo</p></li><li><p><strong>Requisitos de seguridad</strong><br> La operación y el mantenimiento requieren personal capacitado y procedimientos estrictos</p></li><li><p><strong>Configuración del sistema</strong><br> Las configuraciones radial, en lazo o en anillo impactan la confiabilidad y la respuesta ante fallas</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Los sistemas de media tensión reducen el tamaño de los conductores pero aumentan la complejidad del equipo</li><li>Un aislamiento o instalación inadecuados pueden provocar fallas severas e interrupciones</li><li>El mantenimiento y las pruebas son más críticos en comparación con los sistemas de baja tensión</li><li>Las conexiones directas de motores a media tensión son comunes en aplicaciones de alta potencia</li></ul>',23)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
